.panel-card strong {
  display: block;
  font-size: 0.74rem;
  font-weight: 700;
  letter-spacing: 0.18em;
  margin-bottom: 0.35rem;
  text-transform: uppercase;
}

.summary-row span,
.section-meta {
  display: block;
  line-height: 1.6;
}

.section-heading {
  align-items: baseline;
  border-bottom: 1px solid var(--line);
  display: flex;
  flex-wrap: wrap;
  gap: 0.5rem 0.75rem;
  justify-content: space-between;
  margin-bottom: 0.3rem;
  padding-bottom: 0.95rem;
}

.section-meta {
  font-family: var(--font-ui);
  font-size: 0.8rem;
  letter-spacing: 0.06em;
  text-transform: uppercase;
}

.detail-stack {
  margin-top: 1rem;
}

.detail-block {
  background: rgba(255, 255, 255, 0.45);
  border: 1px solid rgba(47, 35, 24, 0.08);
  border-radius: 1.25rem;
  padding: 1rem 1.05rem;
}

.detail-block p {
  margin: 0;
}

.detail-block strong {
  margin-bottom: 0.4rem;
}

.vault-shell {
  width: 100%;
}

.vault-frame {
  background:
    linear-gradient(180deg, rgba(255, 255, 255, 0.44), transparent 24%),
    rgba(250, 245, 237, 0.8);
  display: grid;
  gap: 1.5rem;
  padding: 1.2rem;
}

.vault-frame-header {
  border-bottom: 1px solid var(--line);
  display: grid;
  gap: 1rem;
  padding-bottom: 1.25rem;
}

.vault-frame-note {
  line-height: 1.65;
  margin: 0;
  max-width: 34rem;
}

.vault-frame-body {
  display: grid;
  gap: 1.5rem;
}

.public-home-layout,
.public-note-layout,
.login-layout {
  align-items: start;
}

.public-home-grid,
.dashboard-grid,
.login-layout {
  grid-template-columns: minmax(0, 1fr);
}

.public-side-panel,
.dashboard-side-panel,
.login-form-card {
  align-self: start;
}

.public-hero,
.note-editor-intro {
  overflow: hidden;
}

.note-collection-panel,
.link-list-panel,
.note-preview-panel,
.public-note-card,
.login-form-card {
  background: var(--paper-strong);
}

.public-note-card {
  margin: 0 auto;
  max-width: 56rem;
}

.public-note-header {
  display: grid;
  gap: 0.9rem;
}

.public-note-lede {
  max-width: 36rem;
}

.public-note-metadata {
  background: rgba(133, 80, 51, 0.05);
  border: 1px solid rgba(133, 80, 51, 0.12);
  border-radius: 1.4rem;
  display: grid;
  gap: 1rem;
  margin-top: 1.5rem;
  padding: 1rem 1.05rem;
}

.public-note-body {
  margin-top: 1.1rem;
}

.note-editor-shell {
  margin: 0 auto;
  max-width: 84rem;
}

.note-editor-intro,
.note-form,
.note-preview-panel {
  min-width: 0;
}

.note-form {
  align-content: start;
}

.note-body-field {
  min-height: 0;
}

.text-input,
.note-textarea,
.sign-in-form input {
  background: var(--bg-strong);
  border: 1px solid var(--line);
  border-radius: 1rem;
  color: var(--ink);
  padding: 0.92rem 1rem;
  transition:
    border-color 140ms ease,
    box-shadow 140ms ease,
    background-color 140ms ease;
  width: 100%;
}

.text-input:focus,
.note-textarea:focus,
.sign-in-form input:focus {
  background: #fffdf8;
  border-color: rgba(133, 80, 51, 0.4);
  box-shadow: 0 0 0 0.22rem rgba(133, 80, 51, 0.1);
  outline: none;
}

.note-textarea {
  min-height: 25rem;
  resize: vertical;
}

.summary-textarea {
  min-height: 10rem;
}

.sign-in-form {
  gap: 1rem;
}

.sign-in-form label {
  color: var(--muted);
  display: grid;
  font-size: 0.9rem;
  gap: 0.5rem;
  letter-spacing: 0.03em;
}

.field-group {
  gap: 0.5rem;
}

.field-group span {
  color: var(--muted-soft);
  font-size: 0.82rem;
  letter-spacing: 0.08em;
  text-transform: uppercase;
}

.button-row {
  gap: 0.75rem;
  margin-top: 0.4rem;
}

.primary-button,
.ghost-button {
  align-items: center;
  border-radius: 999px;
  cursor: pointer;
  display: inline-flex;
  font-size: 0.84rem;
  font-weight: 700;
  justify-content: center;
  letter-spacing: 0.12em;
  min-height: 2.85rem;
  padding: 0.72rem 1.1rem;
  text-transform: uppercase;
  transition:
    transform 140ms ease,
    background-color 140ms ease,
    border-color 140ms ease,
    color 140ms ease;
}

.primary-button {
  background: linear-gradient(180deg, #6f4329 0%, var(--accent-strong) 100%);
  border: 1px solid rgba(84, 48, 29, 0.2);
  color: #fff9f2;
  box-shadow: 0 0.85rem 1.5rem rgba(84, 48, 29, 0.16);
}

.ghost-button {
  background: rgba(255, 255, 255, 0.64);
  border: 1px solid var(--line);
  color: var(--ink);
}

.primary-button:focus-visible,
.ghost-button:focus-visible,
.site-nav a:focus-visible,
.vault-nav-link:focus-visible,
.note-list-link:focus-visible,
.tag-filter-link:focus-visible {
  outline: 2px solid rgba(133, 80, 51, 0.35);
  outline-offset: 3px;
}

.status-note {
  background: var(--success-soft);
  border: 1px solid rgba(41, 94, 67, 0.18);
  border-radius: 1rem;
  line-height: 1.6;
  margin: 1rem 0 0;
  padding: 0.9rem 1rem;
}

.status-note-error,
.signin-error {
  background: var(--danger-soft);
  border: 1px solid rgba(124, 52, 44, 0.16);
  border-radius: 1rem;
  color: #6c2e25;
  line-height: 1.6;
  margin: 1rem 0 0;
  padding: 0.9rem 1rem;
}

.auth-note {
  line-height: 1.7;
  margin: 1rem 0 0;
